  ('disabled-6e2f88c7-moex-00047', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '關於普通地上權讓與之敘述，下列何者錯誤？', '["地上權人無須得土地所有人之同意，原則上得自由將其權利讓與他人", "地上權人讓與地上權時，不得與其建築物或工作物分離而為單獨讓與", "地上權人與土地所有人約定地上權不得讓與者，該約定應經登記，始得 對抗第三人", "地租之約定未經登記者，地上權讓與時，受讓人仍應承擔前地上權人積 欠之地租，並連帶負清償責任 30840"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00048', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '下列何者非屬最高限額抵押權所擔保之原債權確定之法定事由？', '["擔保債權之範圍變更，致原債權不繼續發生", "抵押權人經裁定宣告破產", "最高限額抵押權人聲請裁定拍賣抵押物", "擔保債權所由發生之法律關係終止而消滅者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00049', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '下列何者非留置權成立之要件？', '["當事人間須有設定留置權之合意", "債權人須占有他人之動產", "債權之發生與該動產之占有，原則上須有牽連關係", "債權人須非因侵權行為或其他不法之原因而占有動產"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00050', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '在一物一權主義之前提下，有關物權客體之敘述，下列何者錯誤？', '["由多數單一物聚合而具獨立經濟價值之集合物，性質上仍為數個獨立 物，故不得集合為一個所有權之客體", "因違反建築法令而無法請領建築執照之違章建築，縱已符合定著物之要 件，仍不得作為所有權之客體", "土地內之礦產尚未採掘者，為土地之部分，故不得單獨成為所有權之客體", "從物本質上為獨立於主物以外之物，故與主物為個別獨立之兩個所有權 客體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00051', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '甲男乙女於民國 96 年底結婚，公開儀式宴請賓客，但未到戶政機關辦理 結婚登記。2 年後，甲、乙分居。甲與不知情之丙到戶政機關辦理結婚登 記。下列何者正確？', '["甲乙婚姻有效，甲丙婚姻無效", "甲乙婚姻無效，甲丙婚姻有效", "甲乙婚姻有效，甲丙婚姻得撤銷", "甲乙婚姻視為消滅，甲丙婚姻有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00052', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '甲夫乙妻未約定夫妻財產制。甲婚前繼承其父所留A屋，婚後出租累積租 金新臺幣（下同）100 萬元均無動用；甲死亡時，尚有婚後財產存款 600 萬元，其中有因名譽受侵害，獲得慰撫金200萬元。乙於甲死亡時，有婚 後自行購置之珠寶價值100萬元，及乙母贈與之珠寶價值100萬元。關於 剩餘財產分配之敘述，下列何者正確？', '["因屬一身專屬請求權，乙不得向甲之繼承人主張", "乙得向甲請求分配150萬元", "乙得向甲請求分配200萬元", "乙得向甲請求分配300萬元 30840"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00053', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '關於未成年人監護人之敘述，下列何者正確？', '["未成年人之父母死亡而無遺囑指定監護人時，法院即應依職權選任該未 成年子女四親等內之旁系血親尊親屬為監護人", "法院選定監護人時，應依受監護人之最佳利益，審酌一切情狀為之", "未成年子女已滿 16 歲者，監護人縱使未經法院裁定許可，仍得為未成 年人處分其不動產", "監護人之行為與受監護人利益相反時，限於受監護人未滿7歲者，法院 始得依職權，為受監護人選任特別代理人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00054', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '關於遺產繼承人之敘述，下列何者正確？', '["繼承回復請求權與個別物上請求權係屬真正繼承人分別獨立而併存之權利", "繼承人有數人，其中之一人，如有偽造、變造、隱匿或湮滅被繼承人關 於繼承之遺囑者，該繼承人之繼承權喪失。如經其他繼承人宥恕，該繼 承人之繼承權不喪失", "繼承人如有意圖詐害被繼承人之債權人之權利而為遺產之處分，喪失其 繼承權", "繼承人如故意致被繼承人於死，或雖未致死因而受刑之宣告，其繼承權 喪失。但經被繼承人宥恕者，其繼承權不喪失"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00055', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '甲死後留下遺產新臺幣（下同）720 萬元，繼承人乙丙知道甲有對丁之債 務400萬元未清償。乙丙依民法規定陳報遺產清冊，並於公示催告期限後， 全額清償對丁之債務。嗣後有乙丙先前所不知之甲之債權人戊出現，戊主 張其有對甲之債權400萬元未獲清償。下列何者正確？', '["戊得獲償360萬元", "戊得獲償400萬元", "戊得請求丁返還不當受領之40萬元", "戊得獲償320萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL),
  ('disabled-6e2f88c7-moex-00056', 'disabled-6e2f88c7', 'disabled-6e2f88c7-moex-113-9b7ab1bb', 'sub-disabled-6e2f88c7-01', NULL, 'single_choice', '甲男乙女為夫妻，育有一子丙及一女丁，甲不幸過世，乙女尚存，甲留下 新臺幣（下同）1,800萬元之遺產，甲留下之遺產全部皆為婚前財產。甲生 前曾於丁結婚時，贈與600萬元，丙出國留學時，贈與600萬元，於此乙 女可以得到多少遺產？', '["600萬元", "700萬元", "800萬元", "1,000萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:05+00:00", "source_pdf_sha1": "00563b442671", "answer_pdf_sha1": "52df642a00dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "308", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "法制"}'::jsonb, NULL)
